  @impl true
  def handle_call({:create_account, account_id, initial_balance}, _from, %{table: table} = state) do
    case :ets.lookup(table, account_id) do
      [] ->
        :ets.insert(table, {account_id, initial_balance})
        {:reply, {:ok, initial_balance}, state}

      [{^account_id, _balance}] ->
        {:reply, {:error, :account_already_exists}, state}
    end
  end

  @impl true
  def handle_call({:get_balance, account_id}, _from, %{table: table} = state) do
    case :ets.lookup(table, account_id) do
